var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CRIMINAL_NPC_MEMBER_A","text":{"KOREA":"크학......!","JPN":"ぐはっ……！","ENG":"Ack!","TWN":"啊……！"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"CRIMINAL_NPC_MEMBER_A","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CRIMINAL_NPC_MEMBER_B","text":{"KOREA":"형님! 놈들이 워낙 거칠게 저항해서 들어가기 힘듭니다!","JPN":"兄貴！　抵抗が激しく、中に入れそうにありません！","ENG":"Sir! They're fighting too hard for us to make a breach!","TWN":"大哥！他們抵抗太頑強了，無法繼續前進！"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"CRIMINAL_NPC_MEMBER_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CRIMINAL_NPC_MEMBER_B","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"CRIMINAL_NPC_BOSS2_NULL","text":{"KOREA":"이 등신들 같으니...... 구석에 몰아 넣은 들개들도 못 잡아서 빌빌대?","JPN":"使えねえな……追い込んだドブネズミ数匹も始末できねえのか？","ENG":"You good-for-nothing idiots... We've got them cornered!","TWN":"沒用的東西……對方都被逼到死角了，你們還拿他們沒辦法嗎？"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"CRIMINAL_NPC_MEMBER_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CRIMINAL_NPC_MEMBER_B","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"CRIMINAL_NPC_BOSS2_NULL","text":{"KOREA":"뭐 해! 걸리적거리니까 저 멍청한 놈 어서 치워!","JPN":"何やってんだ！　邪魔だからあのバカを早く片付けろ！","ENG":"Don't just stand around! Get that idiot out of the way!","TWN":"愣著幹什麼！快幹掉那個礙眼的傢伙！"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"CRIMINAL_NPC_MEMBER_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CRIMINAL_NPC_MEMBER_B","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"저 녀석들...... 수가 너무 많아. 어쩌지?","JPN":"こいつら……数が多すぎる。どうする？","ENG":"There's too many of them. What should we do?","TWN":"敵人數量……實在太多了。怎麼辦？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"한 놈 죽으면 두 놈 더 늘어나는군. 꽤 작정하고 온 모양인데.","JPN":"一人死んだら二人に増えてくるな。向こうも生半可な気持ちでここまで来たわけではないようだ。","ENG":"We kill one, and they bring two more. Looks like they came prepared.","TWN":"殺一個又冒出兩個，看來他們準備很充分。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"그래, 대장. 이대로 여기서 버티기만 하는 건 자살 행위야.","JPN":"そうだな、隊長。このままここで踏ん張るのは自殺行為だ。","ENG":"That's right, Captain. Holding our ground like this is suicidal.","TWN":"沒錯，隊長。在這裡堅持也是死路一條。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"좋은 방법이라도 있나?","JPN":"いい方法でもあるのか？","ENG":"Got any ideas?","TWN":"你有什麼辦法嗎？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"그야 없진 않지.","JPN":"なくはない。","ENG":"Of course.","TWN":"當然。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"각개 격파라고 들어봤어?","JPN":"各個撃破って聞いたことあるか？","ENG":"Divide and conquer.","TWN":"你知道各個擊破戰術嗎？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"내가 조무래기 놈들을 여기 붙잡아 두는 동안 두 사람은 저 간부 놈을 유인하는 거야.","JPN":"俺が雑魚どもをここで足止めする間、二人はあの幹部の野郎をおびき寄せるんだ。","ENG":"While I keep the rest of the thugs pinned down, you two can lure their leader out.","TWN":"趁我對抗那些嘍囉時，你們兩個去引誘那個幹部。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"쉽게 따라오진 않을 텐데. 그러다가 우리가 각개격파 당할 수도 있어.","JPN":"簡単には釣れないはずだ。逆に俺たちが各個撃破される可能性もある。","ENG":"He won't tag along that easily. They might divide and conquer instead.","TWN":"他們不會輕易上鉤的。說不定被各個擊破的反而會是我們。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"그거야 대장이 알아서 해야지. 남 열 받게 하는 게 대장 특기잖아.","JPN":"そりゃ隊長がなんとかしないと。人を怒らせるのが隊長の特技だろ。","ENG":"Well, that's up to you. You're a pro at aggravating people, you know.","TWN":"那就得靠隊長了。惹毛對方不是你的專長嗎？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"잠깐, 그런데 지훈이 너 혼자 저 많은 놈들을 붙잡아 두겠다고?","JPN":"ちょっと待って、ゴトウ一人であの大人数を足止めするって？","ENG":"Wait, how are you going to keep all those guys pinned down by yourself?","TWN":"等等，你說你要一個人困住那麼多人？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"아까는 대장이 했으니까 이번엔 내 차례지.","JPN":"さっきは隊長がやったから、今度は俺の番だ。","ENG":"That's what the Captain did earlier. It's my turn now.","TWN":"剛才隊長不也成功了嗎，這次輪到我了。"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JIHUN_MILITIA_NULL_NULL","text":{"KOREA":"왜, 대장은 했는데 나는 못 할 것 같아?","JPN":"なんだ、隊長はできて俺にはできないとでも思ってんのか？","ENG":"What, you think I can't do what the Captain did?","TWN":"怎麼，你覺得我做不到嗎？"},"stage":{"bg":"CORRIDOR","slots":{"L":null,"C":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"그런 뜻이 아니잖아! 혼자 개죽음 당하겠다는 거야, 뭐야?!","JPN":"そういう意味じゃない！　一人で無駄死にしたいのか！？","ENG":"That's not what I mean! Are you trying to get yourself killed?!","TWN":"不是這個意思！你這不是找死嗎？！"},"stage":{"bg":"CORRIDOR","slots":{"L":{"char_id":"JIHUN_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_HATE"}}}}]`);export{e as default};